      const beatBurst = params.beatBurst;
      const beatThreshold = params.beatThreshold;
      const ambientRate = params.ambientRate;
      const riseSpeed = params.riseSpeed;
      const drift = params.drift;
      const lifetime = params.lifetime;
      const bassPush = params.bassPush;
      const pointSize = params.particleSize;
      const alphaScale = params.alphaScale;
      material.uniforms.uPointSize.value = pointSize;
      material.uniforms.uAlphaScale.value = alphaScale;
      if (ctx) material.uniforms.uPixelRatio.value = ctx.renderer.getPixelRatio();
      const g2 = params.gradient;
